package main

import (
	"bytes"
	"fmt"
	"os/exec"
	"regexp"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host a user-defined number of times
// and returns the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	// Execute the ping command.
	// -c count: Stop after sending count packets.
	// -W 1: Wait 1 second for a response (timeout).
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), "-W", "1", host)

	var out bytes.Buffer
	var stderr bytes.Buffer
	cmd.Stdout = &out
	cmd.Stderr = &stderr

	err := cmd.Run()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %v: %s", err, stderr.String())
	}

	// Parse the output to find the average latency.
	// Linux ping output typically ends with a line like:
	// rtt min/avg/max/mdev = 1.234/5.678/9.012/1.234 ms
	output := out.String()

	// Regex to find the average time in the statistics line.
	// Matches " = <min>/<avg>/<max>/..." and captures the avg.
	re := regexp.MustCompile(`= ([\d\.]+)/([\d\.]+)/([\d\.]+)/`)
	matches := re.FindStringSubmatch(output)

	if len(matches) < 2 {
		return 0, fmt.Errorf("could not parse ping output to find average latency: %s", output)
	}

	avgStr := matches[2]
	avgLatency, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("could not convert average latency string '%s' to float64: %v", avgStr, err)
	}

	return avgLatency, nil
}

func main() {
	host := "google.com"
	count := 4

	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		return
	}

	fmt.Printf("Average latency for %s over %d pings: %.2f ms\n", host, count, avg)
}

