package main

import (
	"bufio"
	"fmt"
	"os/exec"
	"regexp"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host a given number of times
// and returns the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	// Execute the ping command.
	// -c count: Send 'count' packets.
	// -n: Numeric output only (no DNS resolution, speeds up execution).
	// -W 1: Timeout of 1 second for each response.
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), "-n", "-W", "1", host)

	// Capture the combined output (stdout and stderr).
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %w, output: %s", err, string(output))
	}

	// Parse the output to find the average latency.
	// The ping statistics line typically looks like:
	// round-trip min/avg/max/stddev = 1.234/5.678/9.012/1.234 ms
	// We use a regular expression to find the value between '/' characters in that context.
	scanner := bufio.NewScanner(strings.NewReader(string(output)))
	avgRegex := regexp.MustCompile(`round-trip min/avg/max(?:/stddev)? = [0-9.]+/([0-9.]+)/[0-9.]+`)

	var avgStr string
	for scanner.Scan() {
		line := scanner.Text()
		matches := avgRegex.FindStringSubmatch(line)
		if len(matches) > 1 {
			avgStr = matches[1]
			break
		}
	}

	if avgStr == "" {
		return 0, fmt.Errorf("could not parse average latency from ping output: %s", string(output))
	}

	avgLatency, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to parse latency value '%s': %w", avgStr, err)
	}

	return avgLatency, nil
}

func main() {
	// Example usage
	host := "google.com"
	count := 4

	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		return
	}

	fmt.Printf("Average latency to %s over %d pings: %.2f ms\n", host, count, avg)
}

