package main

import (
	"bytes"
	"fmt"
	"os/exec"
	"regexp"
	"strconv"
)

// MeasureLatency pings the specified host a given number of times
// and returns the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	// Construct the ping command.
	// -c count: Stop after sending count packets.
	// -W 1: Wait 1 second for a response (timeout).
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), "-W", "1", host)

	var out bytes.Buffer
	var stderr bytes.Buffer
	cmd.Stdout = &out
	cmd.Stderr = &stderr

	err := cmd.Run()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %v: %s", err, stderr.String())
	}

	// Parse the output to find the average time.
	// Expected output line usually looks like:
	// round-trip min/avg/max/stddev = 1.234/5.678/9.012/1.234 ms
	// We use a regular expression to extract the average value.
	re := regexp.MustCompile(`round-trip min/avg/max(?:/stddev)? = [\d.]+/([\d.]+)/[\d.]+(?:/[\d.]+)? ms`)
	matches := re.FindStringSubmatch(out.String())

	if len(matches) < 2 {
		return 0, fmt.Errorf("could not parse ping output to find average latency")
	}

	avgStr := matches[1]
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to parse average latency value '%s': %v", avgStr, err)
	}

	return avg, nil
}

func main() {
	// Example usage
	host := "google.com"
	count := 4

	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		return
	}

	fmt.Printf("Average latency for %s: %.2f ms\n", host, avg)
}

