package main

import (
	"bytes"
	"fmt"
	"os/exec"
	"regexp"
	"strconv"
)

// MeasureLatency executes the system ping command to calculate the average network latency.
// It runs the ping command 'count' times against the specified 'host'.
// It returns the average latency in milliseconds or an error if the command fails or output cannot be parsed.
func MeasureLatency(host string, count int) (float64, error) {
	// Construct the ping command. 
	// -c specifies the number of packets to send.
	// -O is used to report "no answer" packets before program exits.
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), "-O", host)

	var out bytes.Buffer
	var stderr bytes.Buffer
	cmd.Stdout = &out
	cmd.Stderr = &stderr

	// Run the command
	err := cmd.Run()
	if err != nil {
		// ping returns exit code 1 if no packets are received, but we might still want partial data.
		// However, for this utility, we generally expect the command to succeed.
		// We will attempt to parse the output regardless, as the summary line is usually present even on failure.
	}

	// Parse the output to find the line containing statistics.
	// Example output line: "round-trip min/avg/max/stddev = 1.234/5.678/9.012/1.234 ms"
	// We use a regular expression to extract the average value.
	// The regex looks for "avg" or just the second number in the sequence min/avg/max/stddev.
	re := regexp.MustCompile(`round-trip.*?=\s*([\d.]+)/([\d.]+)/([\d.]+)/([\d.]+)`)
	matches := re.FindStringSubmatch(out.String())

	if len(matches) < 5 {
		return 0, fmt.Errorf("could not parse ping output. Stdout: %s, Stderr: %s", out.String(), stderr.String())
	}

	// matches[2] corresponds to the average latency (avg)
	avgLatencyStr := matches[2]
	avgLatency, err := strconv.ParseFloat(avgLatencyStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to parse average latency value '%s': %v", avgLatencyStr, err)
	}

	return avgLatency, nil
}

func main() {
	// Example usage
	host := "google.com"
	count := 4

	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		return
	}

	fmt.Printf("Average latency to %s: %.2f ms\n", host, avg)
}

