package main

import (
	"bufio"
	"fmt"
	"os/exec"
	"regexp"
	"strconv"
	"strings"
)

// MeasureLatency executes the system ping command and calculates the average latency.
func MeasureLatency(host string, count int) (float64, error) {
	// Execute the ping command.
	// -c count: Stop after sending count packets.
	// -n: Numeric output only (no DNS resolution), speeds up execution.
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), "-n", host)

	// Capture the combined output (stdout and stderr).
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %w, output: %s", err, string(output))
	}

	// Parse the output to find the average latency.
	// The ping summary line usually looks like:
	// round-trip min/avg/max/stddev = 1.234/5.678/9.012/1.234 ms
	// We use a regular expression to find the "avg" value.
	scanner := bufio.NewScanner(strings.NewReader(string(output)))
	var avgTime float64
	found := false

	// Regex to match the summary line. It looks for 'min/avg/max' pattern.
	re := regexp.MustCompile(`round-trip min/avg/max(?:/stddev)? = [\d.]+/([\d.]+)/[\d.]+`)

	for scanner.Scan() {
		line := scanner.Text()
		matches := re.FindStringSubmatch(line)
		if len(matches) > 1 {
			avgStr := matches[1]
			avgTime, err = strconv.ParseFloat(avgStr, 64)
			if err != nil {
				return 0, fmt.Errorf("failed to parse average latency from string '%s': %w", avgStr, err)
			}
			found = true
			break
		}
	}

	if !found {
		return 0, fmt.Errorf("could not find latency statistics in ping output")
	}

	return avgTime, nil
}

func main() {
	// Example usage
	host := "google.com"
	count := 4

	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		return
	}

	fmt.Printf("Average latency for %s over %d pings: %.2f ms\n", host, count, avg)
}

