package main

import (
	"bytes"
	"fmt"
	"os/exec"
	"regexp"
	"strconv"
)

// MeasureLatency pings the specified host a user-defined number of times
// and returns the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	// Construct the ping command.
	// -c sets the number of packets to send.
	// -n is used to avoid DNS lookups for IP addresses (optional, but good for consistency).
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)

	var out bytes.Buffer
	var stderr bytes.Buffer
	cmd.Stdout = &out
	cmd.Stderr = &stderr

	err := cmd.Run()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %v: %s", err, stderr.String())
	}

	// Parse the output to find the average latency.
	// The ping output line typically looks like:
	// round-trip min/avg/max/stddev = 1.234/5.678/9.012/1.234 ms
	// We use a regular expression to extract the average value.
	// This regex looks for "round-trip ... = X/Y/Z/W ms" and captures the second group (Y).
	re := regexp.MustCompile(`round-trip.*= ([\d\.]+)/([\d\.]+)/([\d\.]+)/([\d\.]+) ms`)
	matches := re.FindStringSubmatch(out.String())

	if matches == nil || len(matches) < 3 {
		return 0, fmt.Errorf("could not parse ping output to find average latency")
	}

	avgStr := matches[2]
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("could not convert average latency string '%s' to float64: %v", avgStr, err)
	}

	return avg, nil
}

func main() {
	// Example usage
