// MeasureLatency executes the system ping command to calculate average network latency.
// It takes the target host and the number of ping attempts as input.
// It returns the average latency in milliseconds or an error if the command fails.
func MeasureLatency(host string, count int) (float64, error) {
	// Construct the ping command.
	// -c specifies the number of packets to send.
	// -q is used to keep the output quiet (summary only), though we will still parse stdout.
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)

	// Run the command and capture the output.
	output, err := cmd.Output()
	if err != nil {
		return 0, fmt.Errorf("ping command execution failed: %w", err)
	}

	// Parse the output to extract the average latency.
	// The output format usually looks like:
	// round-trip min/avg/max/stddev = 1.234/5.678/9.012/1.234 ms
	// We use a regular expression to find the "avg" value.
	// This regex looks for "round-trip", optional text, "=", numbers, "/", the average number, "/", etc.
	re := regexp.MustCompile(`round-trip.*=.*?/([\d\.]+)/`)
	scanner := bufio.NewScanner(strings.NewReader(string(output)))

	var avgLatency float64
	found := false

	for scanner.Scan() {
		line := scanner.Text()
		matches := re.FindStringSubmatch(line)
		if len(matches) > 1 {
			avgStr := matches[1]
			avgLatency, err = strconv.ParseFloat(avgStr, 64)
			if err != nil {
				return 0, fmt.Errorf("failed to parse latency value '%s': %w", avgStr, err)
			}
			found = true
			break
		}
	}

	if !found {
		return 0, fmt.Errorf("could not find latency statistics in ping output")
	}

	return avgLatency, nil
}

func main() {
	// Example usage of the MeasureLatency function.
	host := "google.com"
	count := 4

	fmt.Printf("Pinging %s %d times...\n", host, count)
	latency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		return
	}

	fmt.Printf("Average latency: %.2f ms\n", latency)
