package main

import (
	"bufio"
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
	"strings"
	"time"
)

// MeasureLatency executes the system ping command to calculate average network latency.
// It uses the OS-specific ping command flags (-c for Unix, -n for Windows).
// It also sets a timeout to prevent indefinite hanging.
func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, fmt.Errorf("ping count must be positive")
	}

	var cmd *exec.Cmd

	// Use runtime.GOOS to determine the correct ping flags.
	// This is more reliable than checking command paths or executing test pings.
	if runtime.GOOS == "windows" {
		// Windows: ping -n count host
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		// Unix/Linux/macOS: ping -c count host
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	// Create a buffer to capture combined stdout and stderr
	var output strings.Builder
	cmd.Stdout = &output
	cmd.Stderr = &output

	// Start the command
	if err := cmd.Start(); err != nil {
		return 0, fmt.Errorf("failed to start ping command: %w", err)
	}

	// Wait for the command to finish or timeout
	// Timeout is calculated based on count (approx 2 seconds per ping + buffer)
	done := make(chan error, 1)
	go func() {
		done <- cmd.Wait()
	}()

	timeout := time.Duration(count+2) * time.Second
	select {
	case <-time.After(timeout):
		// Timeout occurred, try to kill the process
		if cmd.Process != nil {
			_ = cmd.Process.Kill()
		}
		return 0, fmt.Errorf("ping command timed out after %v", timeout)
	case err := <-done:
		if err != nil {
			return 0, fmt.Errorf("ping command failed: %w", err)
		}
	}

	// Parse the output to find the average latency.
	// We look for a line containing "average" or "Average".
	// Example Linux output: "rtt min/avg/max/mdev = 1.234/5.678/9.012/1.234 ms"
	// Example Windows output: "Average = 2ms"
	scanner := bufio.NewScanner(strings.NewReader(output.String()))
	re := regexp.MustCompile(`[aA]verage[ =]+([0-9]+\.?[0-9]*)`)

	for scanner.Scan() {
		line := scanner.Text()
		if strings.Contains(line, "average") || strings.Contains(line, "Average") {
			matches := re.FindStringSubmatch(line)
			if len(matches) >= 2 {
				avgStr := matches[1]
				avg, err := strconv.ParseFloat(avgStr, 64)
				if err != nil {
					return 0, fmt.Errorf("failed to parse average latency value: %w", err)
				}
				return avg, nil
			}
		}
	}

	return 0, fmt.Errorf("could not find average latency in ping output")
}

func main() {
	// Example usage
	host := "google.com"
	count := 4

	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		return
	}

	fmt.Printf("Average latency for %s: %.2f ms\n", host, avg)
}

