package main

import (
	"bufio"
	"fmt"
	"os/exec"
	"regexp"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host a given number of times and returns the average latency in ms.
func MeasureLatency(host string, count int) (float64, error) {
	// Execute the ping command.
	// -c sets the count.
	// -n is often used to force numeric output (suppressing DNS lookup), though behavior varies by OS.
	// We assume a standard environment where 'ping' is available.
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)

	// Capture the combined output (stdout and stderr).
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping command: %w", err)
	}

	// Parse the output to find the average latency.
	// The output usually ends with a line like:
	// round-trip min/avg/max/stddev = 1.234/5.678/9.012/1.234 ms
	// We use a regular expression to find this pattern.
	// This regex looks for "round-trip", optional text, "=", numbers separated by "/", and "ms".
	re := regexp.MustCompile(`round-trip.*=.*?([0-9.]+)/([0-9.]+)/([0-9.]+)/([0-9.]+)\s*ms`)

	scanner := bufio.NewScanner(strings.NewReader(string(output)))
	var avgLatencyStr string

	for scanner.Scan() {
		line := scanner.Text()
		matches := re.FindStringSubmatch(line)
		if len(matches) > 2 {
			// matches[1] is min, matches[2] is avg, matches[3] is max, matches[4] is stddev
			avgLatencyStr = matches[2]
			break
		}
	}

	if err := scanner.Err(); err != nil {
		return 0, fmt.Errorf("error reading ping output: %w", err)
	}

	if avgLatencyStr == "" {
		return 0, fmt.Errorf("could not find average latency in ping output: %s", string(output))
	}

	avgLatency, err := strconv.ParseFloat(avgLatencyStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to parse average latency value '%s': %w", avgLatencyStr, err)
	}

	return avgLatency, nil
}

func main() {
	// Example usage
	host := "google.com"
	count := 4

	latency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		return
	}

	fmt.Printf("Average latency for %s: %.2f ms\n", host, latency)
}

