package main

import (
	"bytes"
	"fmt"
	"os/exec"
	"regexp"
	"strconv"
)

// MeasureLatency executes the system ping command to calculate average network latency.
// It returns the average latency in milliseconds or an error if the command fails or output cannot be parsed.
func MeasureLatency(host string, count int) (float64, error) {
	// Execute the ping command.
	// -c count: Stop after sending count packets.
	// -n: Numeric output only (often speeds up execution by skipping DNS lookups on ping replies).
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), "-n", host)

	var out bytes.Buffer
	var stderr bytes.Buffer
	cmd.Stdout = &out
	cmd.Stderr = &stderr

	err := cmd.Run()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %v, stderr: %s", err, stderr.String())
	}

	// Parse the output to find the average latency.
	// The output usually ends with a line like:
	// rtt min/avg/max/mdev = 1.234/5.678/9.012/1.234 ms
	// We use a regular expression to extract the value between the first and second slashes.
	re := regexp.MustCompile(`rtt min/avg/max/mdev = ([\d\.]+)/([\d\.]+)/([\d\.]+)/([\d\.]+) ms`)
	matches := re.FindStringSubmatch(out.String())

	if len(matches) < 3 {
		return 0, fmt.Errorf("could not parse ping output to find average latency")
	}

	avgLatencyStr := matches[2]
	avgLatency, err := strconv.ParseFloat(avgLatencyStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency string '%s' to float: %v", avgLatencyStr, err)
	}

	return avgLatency, nil
}

func main() {
	// Example usage
	host := "google.com"
	count := 4

	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		return
	}

	fmt.Printf("Average latency to %s over %d pings: %.2f ms\n", host, count, avg)
}

