package main

import (
	"bufio"
	"bytes"
	"fmt"
	"os/exec"
	"regexp"
	"strconv"
	"strings"
)

// MeasureLatency executes the system ping command to calculate average network latency.
func MeasureLatency(host string, count int) (float64, error) {
	// Construct the ping command.
	// -c count: Stop after sending count packets.
	// -W 1: Wait 1 second for a response. This prevents the command from hanging indefinitely on unreachable hosts.
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), "-W", "1", host)

	// Run the command and capture stdout and stderr.
	var stdout, stderr bytes.Buffer
	cmd.Stdout = &stdout
	cmd.Stderr = &stderr

	err := cmd.Run()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %v: %s", err, stderr.String())
	}

	// Parse the output to find the average latency.
	// The output typically ends with a line like:
	// rtt min/avg/max/mdev = 1.234/5.678/9.012/1.234 ms
	scanner := bufio.NewScanner(&stdout)
	avgLatency := -1.0
	// Regex to match the ping statistics line.
	// Handles variations in spacing and decimal formats.
	re := regexp.MustCompile(`rtt min/avg/max/mdev[=\s]+([0-9.]+)/([0-9.]+)/([0-9.]+)/([0-9.]+) ms`)

	for scanner.Scan() {
		line := scanner.Text()
		if strings.Contains(line, "avg") {
			matches := re.FindStringSubmatch(line)
			if len(matches) >= 3 {
				// matches[2] corresponds to the average latency group
				val, err := strconv.ParseFloat(matches[2], 64)
				if err == nil {
					avgLatency = val
				}
			}
		}
	}

	if err := scanner.Err(); err != nil {
		return 0, fmt.Errorf("failed to read ping output: %v", err)
	}

	if avgLatency < 0 {
		return 0, fmt.Errorf("could not parse average latency from ping output")
	}

	return avgLatency, nil
}

func main() {
	// Example usage
	host := "google.com"
	count := 4

	latency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		return
	}

	fmt.Printf("Average latency to %s over %d pings: %.2f ms\n", host, count, latency)
}

