package main

import (
	"bufio"
	"fmt"
	"os/exec"
	"regexp"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host a given number of times
// and returns the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	// Construct the ping command.
	// -c count: Send 'count' packets.
	// -n: numeric output only (no DNS resolution), speeds up execution.
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), "-n", host)

	// Run the command and capture the output.
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping command: %w, output: %s", err, string(output))
	}

	// Parse the output to find the average latency.
	// We look for a line that typically looks like:
	// "round-trip min/avg/max/stddev = 1.234/5.678/9.012/1.234 ms"
	// We will use a regular expression to extract the average value.
	scanner := bufio.NewScanner(strings.NewReader(string(output)))
	var avgTime float64
	found := false

	// Regex to match the ping statistics line.
	// Group 1 captures the average latency.
	// This pattern handles variations like "min/avg/max/mdev" or "min/avg/max/stddev".
	re := regexp.MustCompile(`round-trip min/avg/max(?:/stddev|mdev)? = [\d.]+/([\d.]+)/[\d.]+/[\d.]+`)

	for scanner.Scan() {
		line := scanner.Text()
		matches := re.FindStringSubmatch(line)
		if len(matches) > 1 {
			avgTime, err = strconv.ParseFloat(matches[1], 64)
			if err != nil {
				return 0, fmt.Errorf("failed to parse average latency: %w", err)
			}
			found = true
			break
		}
	}

	if !found {
		return 0, fmt.Errorf("could not find latency statistics in ping output")
	}

	return avgTime, nil
}

func main() {
	// Example usage
	host := "google.com"
	count := 4

	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		return
	}

	fmt.Printf("Average latency for %s over %d pings: %.2f ms\n", host, count, avg)
}

