package main

import (
	"bytes"
	"fmt"
	"os/exec"
	"regexp"
	"strconv"
	"strings"
)

// MeasureLatency executes the system ping command to calculate the average round-trip time.
func MeasureLatency(host string, count int) (float64, error) {
	// Execute the ping command.
	// -c count: Stop after sending count packets.
	// -n: Numeric output only (no DNS resolution), speeds up execution.
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), "-n", host)

	var out bytes.Buffer
	cmd.Stdout = &out

	err := cmd.Run()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping command: %w", err)
	}

	// Parse the output to find the average latency.
	// The ping output typically ends with a line like:
	// round-trip min/avg/max/stddev = 1.234/5.678/9.012/1.234 ms
	// We look for the pattern containing "avg".
	output := out.String()

	// Regex to find the statistics line.
	// Group 1 will capture the min/avg/max/stddev string.
	re := regexp.MustCompile(`round-trip min/avg/max(?:/stddev)? = ([\d\.]+)/([\d\.]+)/([\d\.]+)(?:/[\d\.]+)?`)
	matches := re.FindStringSubmatch(output)

	if len(matches) < 4 {
		return 0, fmt.Errorf("could not parse ping output statistics from: %s", output)
	}

	// matches[2] corresponds to the average value.
	avgStr := matches[2]
	avgLatency, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to parse average latency value '%s': %w", avgStr, err)
	}

	return avgLatency, nil
}

func main() {
	// Example usage
	host := "google.com"
	count := 4

	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		return
	}

	fmt.Printf("Average latency for %s (%d pings): %.2f ms\n", host, count, avg)
}

