package main

import (
	"bufio"
	"bytes"
	"fmt"
	"os/exec"
	"regexp"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host a given number of times and returns the average latency in ms.
func MeasureLatency(host string, count int) (float64, error) {
	// Construct the ping command.
	// -c count: Send count packets.
	// -W 1: Wait 1 second for a response (timeout).
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), "-W", "1", host)

	var out bytes.Buffer
	var stderr bytes.Buffer
	cmd.Stdout = &out
	cmd.Stderr = &stderr

	err := cmd.Run()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %v: %s", err, stderr.String())
	}

	// Parse the output to find the average latency.
	// Linux ping output usually ends with a line like:
	// rtt min/avg/max/mdev = 1.234/5.678/9.012/1.234 ms
	scanner := bufio.NewScanner(&out)
	avgLatency := -1.0

	// Regex to capture the average value from the summary line.
	// Matches "min/avg/max/mdev = X/Y/Z/W ms" and captures Y (avg).
	re := regexp.MustCompile(`rtt min/avg/max/mdev = [0-9.]+/([0-9.]+)/[0-9.]+/[0-9.]+ ms`)

	for scanner.Scan() {
		line := scanner.Text()
		if strings.Contains(line, "rtt min/avg/max/mdev") {
			matches := re.FindStringSubmatch(line)
			if len(matches) > 1 {
				val, err := strconv.ParseFloat(matches[1], 64)
				if err == nil {
					avgLatency = val
				}
			}
		}
	}

	if err := scanner.Err(); err != nil {
		return 0, fmt.Errorf("error reading ping output: %v", err)
	}

	if avgLatency < 0 {
		return 0, fmt.Errorf("could not parse average latency from ping output")
	}

	return avgLatency, nil
}

func main() {
	// Example usage
	host := "google.com"
	count := 4

	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		return
	}

	fmt.Printf("Average latency for %s (%d pings): %.2f ms\n", host, count, avg)
}

