package main

import (
	"bytes"
	"fmt"
	"os/exec"
	"regexp"
	"strconv"
)

// MeasureLatency pings the specified host a user-defined number of times
// and returns the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	// Execute the ping command.
	// -c count: Send 'count' packets.
	// -n: numeric output only (often speeds up execution by skipping DNS lookup).
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), "-n", host)

	var out bytes.Buffer
	var stderr bytes.Buffer
	cmd.Stdout = &out
	cmd.Stderr = &stderr

	err := cmd.Run()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %v: %s", err, stderr.String())
	}

	// Parse the output to find the average latency.
	// The ping output typically ends with a line like:
	// round-trip min/avg/max/stddev = 1.234/5.678/9.012/1.234 ms
	// We use a regular expression to extract the average value.
	re := regexp.MustCompile(`round-trip min/avg/max(?:/stddev)? = [\d.]+/([\d.]+)/[\d.]+`)
	matches := re.FindStringSubmatch(out.String())

	if len(matches) < 2 {
		return 0, fmt.Errorf("could not parse average latency from ping output: %s", out.String())
	}

	avgStr := matches[1]
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency string '%s' to float64: %v", avgStr, err)
	}

	return avg, nil
}

func main() {
	// Example usage
	host := "google.com"
	count := 4

	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		return
	}

	fmt.Printf("Average latency for %s over %d pings: %.2f ms\n", host, count, avg)
}

