package main

import (
	"bytes"
	"fmt"
	"os/exec"
	"regexp"
	"strconv"
)

// MeasureLatency pings the specified host a user-defined number of times
// and returns the average latency in milliseconds.
func MeasureLatency(host string, count int) (float64, error) {
	// Execute the ping command.
	// -c count: Stop after sending count packets.
	// On Linux/macOS, ping uses -c. On Windows, it uses -n.
	// This implementation assumes a Linux/macOS environment as per standard Go tooling conventions.
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)

	var out bytes.Buffer
	cmd.Stdout = &out

	err := cmd.Run()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %w", err)
	}

	// Parse the output to find the average latency.
	// Typical ping output line looks like:
	// rtt min/avg/max/mdev = 1.234/5.678/9.012/1.234 ms (Linux)
	// round-trip min/avg/max/stddev = 1.234/5.678/9.012/1.234 ms (BSD/macOS)
	// We use a regex to find the pattern "min/avg/max..." and extract the average.
	re := regexp.MustCompile(`min/avg/max(?:/stddev|mdev)? = [\d.]+/([\d.]+)/[\d.]+`)
	matches := re.FindStringSubmatch(out.String())

	if len(matches) < 2 {
		return 0, fmt.Errorf("could not parse average latency from ping output: %s", out.String())
	}

	avgStr := matches[1]
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency string to float64: %w", err)
	}

	return avg, nil
}

func main() {
	// Example usage
	host := "google.com"
	count := 4

	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		return
	}

	fmt.Printf("Average latency for %s over %d pings: %.2f ms\n", host, count, avg)
}

